framework_css:
/*
    Framework stylesheet replicating an early-2000s boxed corporate layout
    for an industrial wastewater treatment equipment company.
    Visual characteristics based closely on the provided reference design:
    - Fixed-width centered layout with patterned blue outer background
    - White main content box with subtle grey borders
    - Simple bold text navigation below a logo/header strip
    - Blue primary color with red accent and pale blue side tones
*/

:root {
    /* Core color palette (from design brief) */
    --color-primary-1: #2E8DFF; /* bright header/outer background blue */
    --color-primary-2: #003399; /* dark blue for nav text and dividers */

    --color-secondary-1: #E5ECF5; /* pale blue side/box background */
    --color-secondary-2: #99CCFF; /* mid blue highlight */

    --color-accent-1: #CC0000; /* red accent for active links, emphasis */

    --color-neutral-0: #FFFFFF; /* white */
    --color-neutral-1: #F5F5F5; /* light grey */
    --color-neutral-2: #333333; /* main body text */
    --color-border-light: #CCCCCC; /* light borders */
    --color-border-mid: #999999; /* mid borders */

    --color-success: #009900;
    --color-error: #CC0000;
    --color-warning: #FF9900;
    --color-info: #0066CC;

    /* Typography */
    --font-heading: Arial, Helvetica, sans-serif; /* visually similar to original */
    --font-body: Arial, Helvetica, sans-serif;

    --font-size-body: 12px; /* small, dense body text */
    --font-size-small: 11px;
    --font-size-h1: 28px;
    --font-size-h2: 20px;
    --font-size-h3: 16px;

    --line-height-tight: 1.2;
    --line-height-normal: 1.4;
    --line-height-relaxed: 1.6;

    /* Spacing scale (4px base) */
    --space-1: 4px;
    --space-2: 8px;
    --space-3: 12px;
    --space-4: 16px;
    --space-5: 24px;
    --space-6: 32px;

    /* Layout width */
    --layout-width: 980px; /* similar to screenshot */
}

/* Global reset-ish rules */

* {
    box-sizing: border-box;
}

html,
body {
    margin: 0;
    padding: 0;
}

body.site-body {
    font-family: var(--font-body);
    font-size: var(--font-size-body);
    line-height: var(--line-height-normal);
    color: var(--color-neutral-2);
    background-color: var(--color-primary-1);
    /* Diagonal cross-hatch pattern reminiscent of the reference background */
    background-image:
        repeating-linear-gradient(
            45deg,
            rgba(255, 255, 255, 0.18),
            rgba(255, 255, 255, 0.18) 1px,
            transparent 1px,
            transparent 6px
        ),
        repeating-linear-gradient(
            -45deg,
            rgba(255, 255, 255, 0.14),
            rgba(255, 255, 255, 0.14) 1px,
            transparent 1px,
            transparent 6px
        );
}

.site-background {
    padding-top: var(--space-4);
    padding-bottom: var(--space-4);
}

.site-wrapper {
    width: var(--layout-width);
    margin: 0 auto;
    background-color: var(--color-neutral-0);
    border-left: 1px solid var(--color-border-light);
    border-right: 1px solid var(--color-border-light);
    min-height: 100vh;
    display: flex;
    flex-direction: column;
}

/* Header */

.site-header {
    background-color: var(--color-neutral-0);
}

.header-top {
    display: flex;
    justify-content: space-between;
    align-items: flex-end;
    padding: var(--space-4) var(--space-5) var(--space-3);
    background: linear-gradient(to bottom, #FFFFFF 0%, #F5F5F5 40%, #FFFFFF 100%);
    border-bottom: 1px solid var(--color-border-light);
}

.logo-area {
    display: flex;
    flex-direction: column;
}

.logo-text-main {
    font-family: var(--font-heading);
    font-size: 30px;
    font-weight: 700;
    letter-spacing: 1px;
    color: var(--color-primary-2);
    text-transform: uppercase;
}

.logo-text-sub {
    margin-top: var(--space-1);
    font-size: 13px;
    color: var(--color-accent-1);
}

.header-photo-strip {
    display: flex;
    gap: var(--space-2);
}

.header-photo-box {
    width: 140px;
    height: 70px;
    background: linear-gradient(to bottom, #E5ECF5 0%, #99CCFF 50%, #E5ECF5 100%);
    border: 1px solid var(--color-border-light);
}

/* Primary navigation */

.main-nav {
    background-color: var(--color-neutral-0);
    border-bottom: 1px solid var(--color-border-light);
    padding: var(--space-1) var(--space-5) var(--space-1);
}

.main-nav-list {
    list-style: none;
    margin: 0;
    padding: 0;
    white-space: nowrap;
}

.main-nav-item {
    display: inline-block;
    margin-right: var(--space-3);
}

.main-nav-link {
    font-family: var(--font-heading);
    font-size: 13px;
    font-weight: 700;
    color: var(--color-primary-2);
    text-decoration: none;
}

.main-nav-link:hover,
.main-nav-link:focus {
    text-decoration: underline;
}

/* Active state for current page link (apply class on server-side or per page) */

.main-nav-link.is-active {
    color: var(--color-accent-1);
}

/* The blue divider bar under the nav, as in the reference */

.nav-divider-bar {
    height: 4px;
    background: linear-gradient(to bottom,
        var(--color-primary-2) 0%,
        var(--color-primary-2) 50%,
        var(--color-secondary-2) 50%,
        var(--color-secondary-2) 100%
    );
}

/* Main content area */

.site-content {
    flex: 1 0 auto;
    padding: var(--space-4) var(--space-5) var(--space-5);
    background-color: var(--color-neutral-0);
}

.site-content h1,
.site-content h2,
.site-content h3 {
    font-family: var(--font-heading);
    color: var(--color-primary-2);
    margin-top: 0;
}

.site-content h1 {
    font-size: var(--font-size-h1);
    line-height: var(--line-height-tight);
}

.site-content h2 {
    font-size: var(--font-size-h2);
}

.site-content h3 {
    font-size: var(--font-size-h3);
}

.site-content p {
    margin-top: 0;
    margin-bottom: var(--space-3);
}

/* Generic link styling (outside the main nav) */

a {
    color: var(--color-primary-2);
    text-decoration: underline;
}

a:hover,
a:focus {
    color: var(--color-accent-1);
}

/* Footer */

.site-footer {
    flex-shrink: 0;
    border-top: 1px solid var(--color-border-light);
    background-color: var(--color-secondary-1);
}

.footer-links {
    padding: var(--space-3) var(--space-5) var(--space-2);
    font-size: var(--font-size-small);
    text-align: center;
    background-color: #D8E2F0;
    border-bottom: 1px solid var(--color-border-light);
}

.footer-link {
    color: var(--color-primary-2);
    text-decoration: none;
    padding: 0 var(--space-1);
}

.footer-link:hover,
.footer-link:focus {
    text-decoration: underline;
}

.footer-separator {
    color: #777777;
    padding: 0 var(--space-1);
}

.footer-meta {
    padding: var(--space-2) var(--space-5) var(--space-3);
    background-color: var(--color-secondary-1);
}

.footer-copy {
    margin: 0;
    font-size: var(--font-size-small);
    color: #666666;
    text-align: right;
}

/* Utility classes that may be reused by pages (optional) */

.text-accent {
    color: var(--color-accent-1);
}

.text-small {
    font-size: var(--font-size-small);
}

.hr-divider {
    border: 0;
    border-top: 1px solid var(--color-border-light);
    margin: var(--space-4) 0;
}

/* Basic responsive safeguard: keep layout readable on smaller screens
   while retaining the fixed-width look on desktops. */

@media (max-width: 1024px) {
    .site-wrapper {
        width: 100%;
        border-left: none;
        border-right: none;
    }

    .header-top,
    .main-nav,
    .site-content,
    .footer-links,
    .footer-meta {
        padding-left: var(--space-3);
        padding-right: var(--space-3);
    }

    .header-photo-box {
        width: 100px;
        height: 60px;
    }

    .footer-copy {
        text-align: center;
    }
}
